import json

FILES='abcdefgh'
def sq(f,r):
    # f in 0..7, r in 1..8 ; index in 0..63, FEN order (a8=0 .. h1=63)
    return (8-r)*8+f
def onb(f,r):
    return 0<=f<8 and 1<=r<=8
def fl(f):
    return FILES[f]

P_EMPTY=r'\.'
T_ANY=r'[.pnbrq]'      # empty or black non-king (sliding/knight/king dest)
T_ENEMY=r'[pnbrq]'     # black non-king (pawn capture dest)

E1=sq(4,1); A1=sq(0,1); H1=sq(7,1); A8=sq(0,8); H8=sq(7,8)

def cast_clear_for(F,T):
    c=set()
    if F==E1: c|= {0,1}
    if F==A1: c|= {1}
    if F==H1: c|= {0}
    if T==A8: c|= {3}
    if T==H8: c|= {2}
    return c

# ---------- builders ----------
def build_board_groups(conds):
    """Return (pattern_fragment, board_groups) using capturing groups.
    board_groups: list of ('cond', idx, gnum_placeholder) or ('run', None, gph).
    gnum assigned by caller via order; here we just emit groups and return roles."""
    parts=[]; roles=[]
    i=0
    while i<64:
        if i in conds:
            parts.append('('+conds[i]+')')
            roles.append(('cond',i))
            i+=1
        else:
            j=i
            while j<64 and j not in conds: j+=1
            parts.append('(.{%d})'%(j-i))
            roles.append(('run',None))
            i=j
    return ''.join(parts),roles

def build_move_rule(conds,sets,ep_pat='.',ep_out='-',cast_pat=('.','.','.','.'),
                    cast_clear=(),safety_pat='(.....)'):
    boardpat,roles=build_board_groups(conds)
    # assign group numbers
    g=0
    g+=1; safety_g=g
    board_g=[]
    for role in roles:
        g+=1; board_g.append(g)
    cast_g=[]
    for k in range(4):
        g+=1; cast_g.append(g)
    g+=1; ep_g=g
    pat='S\\{'+safety_pat+boardpat
    for k in range(4):
        pat+='('+cast_pat[k]+')'
    pat+='('+ep_pat+')'+'\\}'
    ref=lambda n:'\\g<%d>'%n
    # S reconstruction
    rep='S{'+ref(safety_g)
    for gg in board_g: rep+=ref(gg)
    for gg in cast_g: rep+=ref(gg)
    rep+=ref(ep_g)+'}'
    # M board
    rep+='M{'
    for role,gg in zip(roles,board_g):
        kind,idx=role
        if kind=='cond' and idx in sets:
            rep+=sets[idx]
        else:
            rep+=ref(gg)
    for k,gg in enumerate(cast_g):
        rep+= '-' if k in cast_clear else ref(gg)
    rep+=ep_out+'}'
    return [pat,rep]

def build_probe_rule(slot,attacker):
    boardpat,roles=build_board_groups(attacker)
    g=0; safety_g=[]
    for k in range(5):
        g+=1; safety_g.append(g)
    board_g=[]
    for role in roles:
        g+=1; board_g.append(g)
    g+=1; tail_g=g
    pat='S\\{'+ '(.)'*5 + boardpat + '(.{5})' + '\\}'
    ref=lambda n:'\\g<%d>'%n
    rep='S{'
    for k in range(5):
        rep+= '1' if k==slot else ref(safety_g[k])
    for gg in board_g: rep+=ref(gg)
    rep+=ref(tail_g)+'}'
    return [pat,rep]

def build_check_rule(king_idx,attacker):
    conds=dict(attacker); conds[king_idx]='K'
    parts=[]; i=0
