        if i in conds:
            parts.append(conds[i]); i+=1
        else:
            j=i
            while j<64 and j not in conds: j+=1
            parts.append('.{%d}'%(j-i)); i=j
    boardpat=''.join(parts)
    pat='M(?=\\{'+boardpat+'.....'+'\\})'
    return [pat,'X']

