KN=[(1,2),(2,1),(2,-1),(1,-2),(-1,-2),(-2,-1),(-2,1),(-1,2)]
ORTH=[(1,0),(-1,0),(0,1),(0,-1)]
DIAG=[(1,1),(1,-1),(-1,1),(-1,-1)]

def attack_patterns(f,r):
    pats=[]
    for df,dr in KN:
        nf,nr=f+df,r+dr
        if onb(nf,nr): pats.append({sq(nf,nr):'n'})
    for df in (-1,0,1):
        for dr in (-1,0,1):
            if df==0 and dr==0: continue
            nf,nr=f+df,r+dr
            if onb(nf,nr): pats.append({sq(nf,nr):'k'})
    for df in (-1,1):
        nf,nr=f+df,r+1
        if onb(nf,nr): pats.append({sq(nf,nr):'p'})
    for dirs,cls in [(ORTH,'[rq]'),(DIAG,'[bq]')]:
        for df,dr in dirs:
            inter=[]; d=1
            while True:
                nf,nr=f+df*d,r+dr*d
                if not onb(nf,nr): break
                cond={sq(x,y):P_EMPTY for (x,y) in inter}
                cond[sq(nf,nr)]=cls
                pats.append(cond)
                inter.append((nf,nr)); d+=1
    return pats

